const outputs = [];

for (const item of $input.all()) {
  const email = item.json;
  const binaries = item.binary ?? {};

  const from = typeof email.from === 'string'
    ? email.from
    : email.from?.text ?? email.from?.value?.[0]?.address ?? '';
  const to = typeof email.to === 'string'
    ? email.to
    : email.to?.text ?? (email.to?.value ?? []).map((v) => v.address).filter(Boolean).join(',') ?? '';
  const subject = email.subject ?? '';
  const messageId = email.id ?? email.messageId ?? '';

  for (const [key, bin] of Object.entries(binaries)) {
    const fileName = (bin.fileName || key).toLowerCase();
    if (!/\.(xlsx|xls|csv)$/i.test(fileName)) continue;

    outputs.push({
      json: {
        email_from: from,
        email_subject: subject,
        email_to: to,
        email_message_id: messageId,
        dry_run: 'true',
        binaryPropertyName: 'file',
      },
      binary: {
        file: {
          ...bin,
          fileName: bin.fileName || key,
        },
      },
    });
  }
}

return outputs;

const item = $input.item;
const binaryKeys = Object.keys(item.binary ?? {});
if (binaryKeys.length === 0) {
  throw new Error('Nessun allegato: aggiungi un file binario al trigger di test');
}
const key = binaryKeys[0];
return {
  json: {
    email_from: item.json.from ?? 'test@imment.it',
    email_subject: item.json.subject ?? 'Test bilancino Awentia',
    email_to: item.json.to ?? 'bilanci+awentia@imment.it',
    email_message_id: item.json.messageId ?? `manual-${Date.now()}`,
    dry_run: 'true',
    binaryPropertyName: key,
  },
  binary: item.binary,
};

